#!/usr/bin/env bash
# =============================================================================
# run_experiments_parallel.sh — SEAL leakage experiment sweep (PARALLEL)
#
# Runs all 20 combinations concurrently, one server per experiment on its
# own port so they don't interfere with each other.
#
# Usage:
#   chmod +x run_experiments_parallel.sh
#   ./run_experiments_parallel.sh
#
# Requirements:
#   - input.csv and value_map.json already generated by prep_input.py --se-mode
#   - ChicagoCrimes.csv in the current directory
#   - server.py, client.py, attack.py in the current directory
# =============================================================================

DATASET="ChicagoCrimes.csv"
ATTRIBUTE="Primary Type"
INPUT="input.csv"
VALUE_MAP="value_map.json"
TREE_HEIGHT=7
TRIALS=10
SEED=42
BASE_PORT=65432          # each experiment gets BASE_PORT + run_number

mkdir -p results

# Failsafe: check disk space before starting
AVAILABLE=$(df . | tail -1 | awk '{print $4}')
if [ "$AVAILABLE" -lt 1000000 ]; then
    echo "[ERROR] Less than 1GB free disk space. Clean up and retry."
    exit 1
fi

echo "alpha,padding_x,QRSR,QR_baseline,QRSR_vs_baseline,DRSR,DR_greedy,DRSR_vs_greedy" \
     > results/summary.csv

ALPHAS=(0 1 2 3)
PADDINGS=("none" 2 4 8 16)

# ── Function: run one experiment in the background ────────────────────────
run_one() {
    local alpha=$1
    local padding=$2
    local port=$3

    if [ "$padding" = "none" ]; then
        local label="a${alpha}_xNone"
        local x_flag=""
        local x_display="⊥"
    else
        local label="a${alpha}_x${padding}"
        local x_flag="-x ${padding}"
        local x_display="${padding}"
    fi

    local logfile="results/${label}.jsonl"
    local outfile="results/${label}.txt"
    local oram_out="/dev/null"

    echo "[${label}] Starting on port ${port}..."

    # Start a dedicated server for this experiment
    python3 server.py --port "${port}" > /dev/null 2>&1 &
    local server_pid=$!
    sleep 1

    # Run client
    python3 client.py "${INPUT}" "${oram_out}" \
        -a "${alpha}" \
        -l "${TREE_HEIGHT}" \
        ${x_flag} \
        --port "${port}" \
        --query-log "${logfile}" \
        > /dev/null 2>&1

    # Kill this experiment's server
    kill "${server_pid}" 2>/dev/null || true
    wait "${server_pid}" 2>/dev/null || true

    # Run attack
    python3 attack.py \
        --dataset "${DATASET}" \
        --attribute "${ATTRIBUTE}" \
        --query-log "${logfile}" \
        --value-map "${VALUE_MAP}" \
        --trials "${TRIALS}" \
        --seed "${SEED}" \
        --json-out "results/${label}.json" \
        > "${outfile}" 2>&1

    # Extract numbers
    if [ -f "results/${label}.json" ]; then
        local numbers
        numbers=$(python3 -c "
import json
with open('results/${label}.json') as f: d=json.load(f)
qr = d.get('query_recovery', {})
dr = d.get('database_recovery', {})
qrsr     = qr.get('qrsr', 0) * 100
baseline = qr.get('baseline', 0) * 100
drsr     = dr.get('drsr', 0) * 100
greedy   = dr.get('greedy', 0) * 100
ratio_qr = qrsr / baseline if baseline > 0 else 0
ratio_dr = drsr / greedy   if greedy  > 0 else 0
print(f'{qrsr:.2f},{baseline:.2f},{ratio_qr:.2f},{drsr:.2f},{greedy:.2f},{ratio_dr:.2f}')
")
        # Write to a temp file (avoid race conditions on summary.csv)
        echo "${alpha},${x_display},${numbers}" > "results/${label}.csv_row"
        echo "[${label}] Done — QRSR=$(echo $numbers | cut -d',' -f1)%"
    else
        echo "${alpha},${x_display},ERROR,ERROR,ERROR,ERROR,ERROR,ERROR" \
             > "results/${label}.csv_row"
        echo "[${label}] ERROR — check ${outfile}"
    fi
}

# ── Launch all 20 experiments in parallel ─────────────────────────────────
echo "Launching all 20 experiments in parallel..."
echo "(Each gets its own server on a separate port)"
echo ""

pids=()
port=$BASE_PORT

for alpha in "${ALPHAS[@]}"; do
    for padding in "${PADDINGS[@]}"; do
        run_one "${alpha}" "${padding}" "${port}" &
        pids+=($!)
        port=$((port + 1))
    done
done

# ── Wait for all to finish ─────────────────────────────────────────────────
echo "Waiting for all experiments to complete..."
for pid in "${pids[@]}"; do
    wait "${pid}"
done

# ── Assemble summary.csv in order ─────────────────────────────────────────
for alpha in "${ALPHAS[@]}"; do
    for padding in "${PADDINGS[@]}"; do
        if [ "$padding" = "none" ]; then
            label="a${alpha}_xNone"
        else
            label="a${alpha}_x${padding}"
        fi
        if [ -f "results/${label}.csv_row" ]; then
            cat "results/${label}.csv_row" >> results/summary.csv
            rm "results/${label}.csv_row"
        fi
    done
done

# ── Print summary ──────────────────────────────────────────────────────────
echo ""
echo "================================================================"
echo "ALL EXPERIMENTS COMPLETE"
echo "================================================================"
echo ""
column -t -s',' results/summary.csv 2>/dev/null || cat results/summary.csv
echo ""
echo "Individual results in results/*.txt"
